// ─── Layout rect ─────────────────────────────────────────────────────────────
#[derive(Clone, Copy, Debug)]
struct Rect { x: f64, y: f64, w: f64, h: f64 }
impl Rect {
    #[inline]
    fn hit(self, px: f64, py: f64) -> bool {
        px >= self.x && px < self.x + self.w && py >= self.y && py < self.y + self.h
    }
    #[inline]
    fn pad(self, t: f64, r: f64, b: f64, l: f64) -> Rect {
        Rect { x: self.x+l, y: self.y+t, w: self.w-l-r, h: self.h-t-b }
    }
}

// ─── Spring physics (ved runtime) ────────────────────────────────────────────
#[derive(Clone, Copy)]
struct Spring { x: f64, v: f64, k: f64, d: f64, m: f64 }
impl Spring {
    fn new(k: f64, d: f64, m: f64) -> Self { Self { x: 0.0, v: 0.0, k, d, m } }
    /// Step toward target. Returns true when settled.
    fn tick(&mut self, target: f64, dt: f64) -> bool {
        let a = (-self.k * (self.x - target) - self.d * self.v) / self.m;
        self.v += a * dt;
        self.x += self.v * dt;
        (self.x - target).abs() < 0.001 && self.v.abs() < 0.001
    }
}

