// ─── Tap action dispatch (generated from VED `on tap` bodies) ────────────────
fn dispatch(id: u32) {
    match id {
        0 => {
            st().counter_count = (st().counter_count - 1);
        }
        1 => {
            st().counter_count = (st().counter_count + 1);
        }

        _ => {}
    }
}

// ─── Render dispatcher ───────────────────────────────────────────────────────
fn do_render() {
    unsafe { VED_TAPS.clear(); }
    unsafe { ved_clear(10, 10, 10); }
    render_counter();
}

